import{c as s,Q as e,j as a,m as i}from"./chunks/framework.D9IbVcwA.js";const k=JSON.parse('{"title":"027-fs-vfs-2 · VFS 虚拟文件系统","description":"","frontmatter":{"title":"027-fs-vfs-2 · VFS 虚拟文件系统"},"headers":[],"relativePath":"hands-on/027-fs-vfs-2.md","filePath":"hands-on/027-fs-vfs-2.md","lastUpdated":1779686691000}'),n={name:"hands-on/027-fs-vfs-2.md"};function r(o,t,l,p,d,h){return e(),a("div",null,[...t[0]||(t[0]=[i(`<h1 id="_027-2-hands-on-挂载点表与路径解析-—-vfs-的路由器" tabindex="-1">027-2 Hands-on: 挂载点表与路径解析 — VFS 的路由器 <a class="header-anchor" href="#_027-2-hands-on-挂载点表与路径解析-—-vfs-的路由器" aria-label="Permalink to &quot;027-2 Hands-on: 挂载点表与路径解析 — VFS 的路由器&quot;">​</a></h1><h2 id="导语" tabindex="-1">导语 <a class="header-anchor" href="#导语" aria-label="Permalink to &quot;导语&quot;">​</a></h2><p>上一章我们搭好了 VFS 的数据结构地基：Inode、InodeOps、FileSystem 基类、File、FDTable。但光有这些还不够——当 sys_open(&quot;/hello.txt&quot;) 被调用时，内核怎么知道应该去找 Ramdisk 还是 ext2？答案是挂载点表（Mount Table），它就像一个路由器：把文件路径前缀映射到对应的文件系统后端，路径解析时做最长前缀匹配，找到正确的后端后把剩余的相对路径交给它处理。</p><p>同时，这一章我们还要实现内核自己的字符串函数库（memset/memcpy/strcmp 等），因为挂载点表和路径解析需要大量字符串操作，而 freestanding 环境下没有标准 libc 可用。完成本章后，我们就能把一个 Ramdisk 实例注册到挂载点表里，通过 vfs_resolve 把任意路径路由到正确的文件系统后端。</p><p>知识前置：需要完成 027-1（VFS 数据结构设计）和 026（Ramdisk）。</p><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="挂载点表-—-vfs-的路由器" tabindex="-1">挂载点表 — VFS 的路由器 <a class="header-anchor" href="#挂载点表-—-vfs-的路由器" aria-label="Permalink to &quot;挂载点表 — VFS 的路由器&quot;">​</a></h3><p>挂载点表的核心思路用一句话就能说清：把一个路径前缀绑定到一个 FileSystem 实例。比如把 &quot;/&quot; 绑定到 Ramdisk、把 &quot;/mnt/disk&quot; 绑定到 ext2——当用户调用 open(&quot;/mnt/disk/readme.txt&quot;) 时，VFS 先在挂载点表里找最长的匹配前缀 &quot;/mnt/disk&quot;，然后把剩余的相对路径 &quot;readme.txt&quot; 交给 ext2 的 lookup() 处理。</p><p>这种&quot;最长前缀匹配&quot;的设计和 Linux 的 mount 命令行为一致：如果 &quot;/&quot; 和 &quot;/mnt/disk&quot; 都有挂载，那 &quot;/mnt/disk/file&quot; 会匹配到 &quot;/mnt/disk&quot; 而不是 &quot;/&quot;，因为前者前缀更长、更精确。OSDev Wiki 把这种设计叫做&quot;Mount Point List&quot;模型——简单、直观，虽然在大规模挂载时性能不如 Node Graph，但对教学 OS 来说绰绰有余。</p><h3 id="路径边界检查-—-最容易被忽略的细节" tabindex="-1">路径边界检查 — 最容易被忽略的细节 <a class="header-anchor" href="#路径边界检查-—-最容易被忽略的细节" aria-label="Permalink to &quot;路径边界检查 — 最容易被忽略的细节&quot;">​</a></h3><p>最长前缀匹配有一个微妙的问题：如果挂载了 &quot;/mnt&quot;，那 &quot;/mntdata/file&quot; 不应该匹配到 &quot;/mnt&quot;。我们需要确保前缀匹配发生在路径组件边界上——也就是说，匹配前缀的下一个字符必须是 &#39;/&#39; 或者 &#39;\\0&#39;（字符串结束），又或者挂载路径本身以 &#39;/&#39; 结尾（比如 &quot;/&quot; 挂载点，任何以 &quot;/&quot; 开头的路径都匹配）。</p><h3 id="内核字符串库-—-freestanding-的必修课" tabindex="-1">内核字符串库 — freestanding 的必修课 <a class="header-anchor" href="#内核字符串库-—-freestanding-的必修课" aria-label="Permalink to &quot;内核字符串库 — freestanding 的必修课&quot;">​</a></h3><p>在 freestanding 环境下（没有标准库），你必须自己实现 memset、memcpy、memmove、memcmp、strcmp、strncmp、strlen 这些最基础的函数。它们都放在 <code>kernel/lib/string.hpp</code> 和 <code>string.cpp</code> 里，用 extern &quot;C&quot; 链接，这样既能被 C++ 代码直接调用，也能被可能存在的 C 代码链接。memmove 需要处理源和目标重叠的情况——当目标地址小于源地址时正向拷贝，反之则反向拷贝。</p><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-1-实现内核字符串函数库" tabindex="-1">Step 1: 实现内核字符串函数库 <a class="header-anchor" href="#step-1-实现内核字符串函数库" aria-label="Permalink to &quot;Step 1: 实现内核字符串函数库&quot;">​</a></h3><p><strong>目标</strong>: 创建 <code>kernel/lib/string.hpp</code> 和 <code>kernel/lib/string.cpp</code>，实现 9 个基础函数。</p><p><strong>设计思路</strong>: 所有函数声明在 extern &quot;C&quot; 块内，匹配标准 libc 签名。memset 逐字节填充；memcpy 逐字节拷贝（用 <strong>restrict</strong> 告诉编译器 src 和 dest 不重叠）；memmove 先判断地址大小关系再决定拷贝方向；memcmp 逐字节比较；strcmp 和 strncmp 逐字符比较到 &#39;\\0&#39;；strlen 遍历到 &#39;\\0&#39; 计数；strcpy 拷贝字符串；utoa 把 uint32_t 转成十进制字符串。</p><p><strong>实现约束</strong>: 不要试图用 SIMD 优化这些函数——对于内核来说，简单的逐字节实现就够了，可读性和正确性远比性能重要。memcpy 的 <strong>restrict</strong> 是 GCC 扩展，告诉编译器 src 和 dest 指向的内存不重叠，允许更好的优化。</p><p><strong>踩坑预警</strong>: memmove 是唯一一个需要正确处理重叠的函数。如果 dest &gt; src 且有重叠区域，正向拷贝会覆盖还没读到的数据——必须反向拷贝。如果 dest &lt; src，正向拷贝是安全的。如果 dest == src，什么都不做直接返回。</p><p><strong>验证</strong>: 编译通过后，可以在 host 测试中验证——创建 test 文件调用 memset/memcpy/memcmp 等，确认返回值和内存状态符合预期。</p><h3 id="step-2-定义-mountpoint-结构和挂载点表接口" tabindex="-1">Step 2: 定义 MountPoint 结构和挂载点表接口 <a class="header-anchor" href="#step-2-定义-mountpoint-结构和挂载点表接口" aria-label="Permalink to &quot;Step 2: 定义 MountPoint 结构和挂载点表接口&quot;">​</a></h3><p><strong>目标</strong>: 创建 <code>kernel/fs/vfs_mount.hpp</code>，定义挂载点表的数据结构和操作函数。</p><p><strong>设计思路</strong>: MountPoint 结构包含三个字段——path（char 数组，256 字节，存储挂载路径如 &quot;/&quot; 或 &quot;/mnt&quot;）、fs（FileSystem 指针，指向具体的文件系统后端实例）、in_use（bool 标志，表示这个槽位是否被占用）。挂载点表是全局的固定大小数组（8 个槽位，MOUNT_TABLE_SIZE = 8），对教学 OS 来说足够了。</p><p><strong>实现约束</strong>: 四个操作函数——vfs_mount_init()（清空所有槽位）、vfs_mount_add(path, fs)（找到空槽位、拷贝路径、设置 fs 和 in_use）、vfs_mount_remove(path)（找到匹配路径的槽位、置 in_use=false）、vfs_resolve(path, &amp;rel_path)（最长前缀匹配、返回 FileSystem* 并设置 rel_path 指向剩余路径）。</p><p><strong>踩坑预警</strong>: vfs_mount_add 需要手动计算路径长度（不能用 strlen，因为此时可能还在初始化阶段）——实际上我们已经有了自己实现的 strlen，可以直接用。路径长度不能超过 MOUNT_PATH_MAX（256），否则返回 false。</p><p><strong>验证</strong>: 编译通过。</p><h3 id="step-3-实现-vfs-resolve-—-最长前缀匹配" tabindex="-1">Step 3: 实现 vfs_resolve — 最长前缀匹配 <a class="header-anchor" href="#step-3-实现-vfs-resolve-—-最长前缀匹配" aria-label="Permalink to &quot;Step 3: 实现 vfs_resolve — 最长前缀匹配&quot;">​</a></h3><p><strong>目标</strong>: 在 <code>kernel/fs/vfs_mount.cpp</code> 中实现 vfs_resolve 函数。</p><p><strong>设计思路</strong>: 遍历挂载点表的所有 in-use 条目，对每个条目用 strncmp 检查路径是否以挂载路径开头。如果匹配，再检查路径边界——挂载路径最后一个字符是 &#39;/&#39; 的话直接算匹配成功，否则要求路径中紧接前缀的下一个字符是 &#39;/&#39; 或 &#39;\\0&#39;。记录最长匹配的条目，最终返回其 FileSystem 指针，并设置 rel_path 指向 path + 前缀长度。</p><p><strong>实现约束</strong>: rel_path 是输出参数——如果找到匹配，*rel_path 被设为 path + best_len（指向剥离前缀后的剩余路径）。如果没找到任何匹配，返回 nullptr。比如 &quot;/&quot; 挂载 Ramdisk，解析 &quot;/hello.txt&quot; 时，rel_path 指向 &quot;hello.txt&quot;。</p><p><strong>踩坑预警</strong>: 当挂载路径是 &quot;/&quot; 时，best_len = 1，rel_path 指向 &quot;hello.txt&quot;——这是正确的。但如果挂载路径是 &quot;/mnt&quot;（没有尾随斜杠），解析 &quot;/mnt/file&quot; 时 best_len = 4，rel_path 应该指向 &quot;/file&quot;——等等，这不对！实际上 rel_path 应该指向挂载点之后的路径部分。如果挂载路径是 &quot;/mnt&quot;，解析 &quot;/mnt/file&quot; 时，剥离 &quot;/mnt&quot; 后 rel_path 指向 &quot;/file&quot;，这时候 ext2 的 lookup 需要能处理前导 &#39;/&#39;。Cinux 的做法是让 Ramdisk 的 lookup 在比较前先跳过前导 &#39;/&#39;——简单粗暴但管用。</p><p><strong>验证</strong>:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test_vfs_mount</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ctest</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vfs_mount</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --output-on-failure</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>预期：19 个测试全部通过，包括最长前缀匹配测试。</p><h3 id="step-4-实现-g-global-fd-table-和-current-fd-table" tabindex="-1">Step 4: 实现 g_global_fd_table 和 current_fd_table <a class="header-anchor" href="#step-4-实现-g-global-fd-table-和-current-fd-table" aria-label="Permalink to &quot;Step 4: 实现 g_global_fd_table 和 current_fd_table&quot;">​</a></h3><p><strong>目标</strong>: 在 vfs_mount.cpp 中实现返回 FDTable 引用的函数。</p><p><strong>设计思路</strong>: g_global_fd_table() 使用函数内的 static 局部变量实现延迟初始化——第一次调用时构造，之后每次返回同一个引用。current_fd_table() 是更高级的访问器——先尝试获取当前任务的 per-process FDTable，如果不存在就回退到全局 FDTable。在 milestone 027 阶段所有任务都使用全局 FDTable。</p><p><strong>实现约束</strong>: g_global_fd_table() 返回类型是 FDTable&amp;（引用）。current_fd_table() 在内核态先查询 Scheduler::current() 获取当前任务的 fd_table，在 host 测试中直接回退到全局 FDTable。这两个函数都需要 __cxa_guard_acquire/release 的支持（我们已经在 crt_stub.cpp 中实现了）。</p><p><strong>踩坑预警</strong>: 如果没有实现 __cxa_guard_acquire/release，链接时会报 undefined reference 错误。这两个函数是 C++ ABI 的一部分，GCC 在编译函数内 static 变量时会自动生成对它们的调用。在 freestanding 环境下必须手动提供。</p><p><strong>验证</strong>: 编译通过。g_global_fd_table() 多次调用应返回同一个对象的地址。</p><h3 id="step-5-更新-kernel-main-cpp-—-初始化-vfs" tabindex="-1">Step 5: 更新 kernel/main.cpp — 初始化 VFS <a class="header-anchor" href="#step-5-更新-kernel-main-cpp-—-初始化-vfs" aria-label="Permalink to &quot;Step 5: 更新 kernel/main.cpp — 初始化 VFS&quot;">​</a></h3><p><strong>目标</strong>: 在 kernel_main() 中添加 VFS 初始化代码。</p><p><strong>设计思路</strong>: 把 Ramdisk 实例从局部变量改为 static（避免栈溢出，而且生命周期需要覆盖整个运行期），然后依次调用 vfs_mount_init() 和 vfs_mount_add(&quot;/&quot;, &amp;ramdisk) 把 Ramdisk 注册到挂载点表的根路径。</p><p><strong>实现约束</strong>: Ramdisk 的 mount() 现在返回 bool 而非 uint32_t，需要检查返回值。如果 mount 失败，打印错误信息但不 panic——内核仍然可以运行（只是没有文件系统可用）。</p><p><strong>验证</strong>:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> big_kernel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">qemu-system-x86_64</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -serial</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stdio</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -kernel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> big_kernel.bin</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;&amp;1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;(VFS|RAMDISK|Milestone)&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>预期看到 &quot;[VFS] Ramdisk mounted at /&quot; 和之前一样的 Ramdisk 文件列表输出。</p><h2 id="构建与运行" tabindex="-1">构建与运行 <a class="header-anchor" href="#构建与运行" aria-label="Permalink to &quot;构建与运行&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test_host</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>预期：所有 host 测试通过，包括新增的 test_vfs_mount（19 个用例）。QEMU 内核测试中会看到 VFS 初始化的串口输出。</p><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><p><strong>vfs_resolve 返回 nullptr</strong>: 检查是否调用了 vfs_mount_init()——如果表没初始化，所有槽位的 in_use 都是未定义的垃圾值，resolve 可能匹配到错误条目或直接崩溃。确保 init 在 add 之前调用。</p><p><strong>路径匹配到了错误的文件系统</strong>: 最常见的原因是忘记做路径边界检查。比如挂载了 &quot;/mnt&quot; 后，&quot;/mnt2/file&quot; 也被匹配到了 &quot;/mnt&quot;。检查 strncmp 的长度参数和后续的边界字符判断是否正确。</p><p><strong>__cxa_guard_acquire 链接失败</strong>: 确认 kernel/arch/x86_64/crt_stub.cpp 中有这两个函数的实现。它们必须在 extern &quot;C&quot; 链接下，因为编译器生成的调用使用的是 C 链接名。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>要点</th></tr></thead><tbody><tr><td>MountPoint</td><td>路径前缀 + FileSystem 指针 + in_use 标志</td></tr><tr><td>挂载点表</td><td>固定 8 槽位的全局数组</td></tr><tr><td>vfs_mount_init/add/remove</td><td>初始化、注册、注销挂载点</td></tr><tr><td>vfs_resolve</td><td>最长前缀匹配 + 路径边界检查，返回 FileSystem* 和相对路径</td></tr><tr><td>路径边界</td><td>前缀后的字符必须是 &#39;/&#39; 或 &#39;\\0&#39;，或者前缀以 &#39;/&#39; 结尾</td></tr><tr><td>g_global_fd_table</td><td>返回全局 FDTable 引用，static 延迟初始化</td></tr><tr><td>current_fd_table</td><td>先查 per-process FDTable，回退到全局 FDTable</td></tr><tr><td>string.cpp</td><td>9 个 freestanding 字符串/内存函数，extern &quot;C&quot; 链接</td></tr></tbody></table>`,56)])])}const m=s(n,[["render",r]]);export{k as __pageData,m as default};
